import{_ as a,c as o,o as e,a1 as i}from"./chunks/framework.DDNAyvCW.js";const l="/assets/shortcut-command-demo.BRY6qC3r.gif",r="/assets/macro-recording-demo.BxqMyqPM.gif",g=JSON.parse('{"title":"快捷命令","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/snippets/index.md","filePath":"docs/terminal/snippets/index.md"}'),d={name:"docs/terminal/snippets/index.md"};function n(s,t,c,h,u,p){return e(),o("div",null,t[0]||(t[0]=[i('<h1 id="快捷命令" tabindex="-1">快捷命令 <a class="header-anchor" href="#快捷命令" aria-label="Permalink to &quot;快捷命令&quot;">​</a></h1><p>将常用命令保存为可复用的快捷命令，在终端的快捷命令栏中一键执行。</p><p><img src="'+l+'" alt="快捷命令执行示意"></p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>快捷命令栏显示在终端输入区域上方。每个快捷命令显示名称和执行按钮。点击按钮将命令插入终端，然后按回车键执行。</p><h2 id="创建快捷命令" tabindex="-1">创建快捷命令 <a class="header-anchor" href="#创建快捷命令" aria-label="Permalink to &quot;创建快捷命令&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>从快捷命令栏打开快捷命令管理器。</li><li>点击 <strong>创建快捷命令</strong>（或&quot;+&quot;按钮）。</li><li>填写以下字段： <ul><li><strong>名称</strong> -- 简短的描述性标签（例如：&quot;检查磁盘使用&quot;）。</li><li><strong>分组</strong> -- 将快捷命令分配到一个组以便组织（例如：&quot;监控&quot;、&quot;部署&quot;）。</li><li><strong>命令</strong> -- 要执行的 Shell 命令或多命令脚本。</li></ul></li><li>保存快捷命令。它会出现在快捷命令栏中。</li></ol><h3 id="快捷命令示例" tabindex="-1">快捷命令示例 <a class="header-anchor" href="#快捷命令示例" aria-label="Permalink to &quot;快捷命令示例&quot;">​</a></h3><p>以下是值得创建的实用快捷命令：</p><table tabindex="0"><thead><tr><th>名称</th><th>命令</th><th>用途</th></tr></thead><tbody><tr><td>磁盘使用</td><td><code>df -h</code></td><td>快速检查文件系统使用情况</td></tr><tr><td>高内存进程</td><td><code>ps aux --sort=-%mem | head -20</code></td><td>查找内存占用最高的 20 个进程</td></tr><tr><td>实时日志</td><td><code>tail -f /var/log/app/application.log</code></td><td>实时跟踪应用日志</td></tr><tr><td>重启 Nginx</td><td><code>sudo systemctl restart nginx &amp;&amp; sudo systemctl status nginx</code></td><td>重启并验证 nginx 状态</td></tr><tr><td>备份配置</td><td><code>cp /etc/nginx/nginx.conf /etc/nginx/nginx.conf.bak</code></td><td>编辑前备份配置文件</td></tr><tr><td>Docker 清理</td><td><code>docker system prune -af --volumes</code></td><td>删除未使用的 Docker 镜像、容器和卷</td></tr></tbody></table><h2 id="宏录制" tabindex="-1">宏录制 <a class="header-anchor" href="#宏录制" aria-label="Permalink to &quot;宏录制&quot;">​</a></h2><p>您可以录制一系列终端操作，自动将其保存为快捷命令，而无需手动输入命令。</p><p><img src="'+r+'" alt="宏录制示意"></p><h3 id="如何录制宏" tabindex="-1">如何录制宏 <a class="header-anchor" href="#如何录制宏" aria-label="Permalink to &quot;如何录制宏&quot;">​</a></h3><ol><li>点击快捷命令栏中的 <strong>录制</strong> 按钮开始录制。</li><li>在终端中正常执行您想要捕获的命令。</li><li>完成后点击 <strong>停止录制</strong>。</li><li>Chaterm 会根据录制的命令生成快捷命令。</li><li>为快捷命令命名并选择分组，然后保存。</li></ol><p>宏录制特别适合捕获您经常执行的多步骤工作流，例如部署流程或环境配置步骤。</p><h2 id="管理快捷命令" tabindex="-1">管理快捷命令 <a class="header-anchor" href="#管理快捷命令" aria-label="Permalink to &quot;管理快捷命令&quot;">​</a></h2><h3 id="命令分组" tabindex="-1">命令分组 <a class="header-anchor" href="#命令分组" aria-label="Permalink to &quot;命令分组&quot;">​</a></h3><p>将快捷命令组织到不同分组中，便于管理：</p><ul><li><strong>监控</strong> -- 系统状态、日志、资源使用。</li><li><strong>部署</strong> -- 构建、部署、回滚命令。</li><li><strong>数据库</strong> -- 备份、恢复、查询命令。</li><li><strong>网络</strong> -- 连通性检查、防火墙规则。</li></ul><h3 id="编辑和删除" tabindex="-1">编辑和删除 <a class="header-anchor" href="#编辑和删除" aria-label="Permalink to &quot;编辑和删除&quot;">​</a></h3><ul><li>点击快捷命令可以编辑其名称、分组或命令内容。</li><li>删除不再需要的快捷命令，保持快捷命令栏整洁。</li></ul><h2 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h2><ul><li><strong>结合 AI 使用。</strong> 使用 <a href="/docs/terminal/chattoai/">Chat to AI</a> 生成命令，然后将其保存为快捷命令以便日后使用。</li><li><strong>使用多命令快捷命令。</strong> 用 <code>&amp;&amp;</code> 连接多个命令，创建可靠的多步骤操作（链中任一命令失败则停止执行）。</li><li><strong>命名要清晰。</strong> 使用描述性名称，以便在快捷命令栏中一目了然。</li><li><strong>避免存储敏感信息。</strong> 切勿在快捷命令中直接存放密码、令牌或 API 密钥。请使用环境变量或密钥管理器。</li></ul><div class="warning custom-block"><p class="custom-block-title">安全提示</p><ul><li>执行前请检查快捷命令内容，特别是编辑后的命令。</li><li>避免在快捷命令中包含敏感信息（密码、令牌）。</li><li>在生产环境运行前，先在测试环境中验证有风险的命令。</li><li>定期审查快捷命令，删除不再需要的命令。</li></ul></div>',26)]))}const q=a(d,[["render",n]]);export{g as __pageData,q as default};
